member.example:
    // 아래의 예외가 반환하는 문자열

    var exceptions =
        new Exception("AAA",
            new Exception("BBB",
                new Exception("CCC",
                    new AggregateException("DDD",
                        new[]
                        {
                            new Exception("DDD 1", new Exception("DDD 1-1")),
                            new Exception("DDD 2")
                        }))));
// Result: exceptions.ToExceptionMessages() 결과
// Exception:AAA -> Exception:BBB -> Exception:CCC -> AggregateException:DDD (DDD 1) (DDD 2) -> Exception:DDD 1 -> Exception:DDD 1-1 -> Exception:DDD 2
//
// Result: catch 절에서 exception.ToString() 결과
// System.Exception: AAA
// --- System.Exception: BBB
// --- System.Exception: CCC
// --- System.AggregateException: DDD (DDD 1) (DDD 2)
// --- System.Exception: DDD 1
// --- System.Exception: DDD 1-1
// --- End of inner exception stack trace ---
// --- End of inner exception stack trace ---
// --- (Inner Exception #1) System.Exception: DDD 2---
// --- End of inner exception stack trace ---
// --- End of inner exception stack trace ---
// --- End of inner exception stack trace ---
// at Program.Main$(String[] args)
